#include <bits/stdc++.h>
using namespace std;
const int  maxn=1e6+5;
int son[maxn][65];
int cnt[maxn],idx,ennd[maxn];
int get_id(char c) {
	return c-'0';
}
void insert(string &s) {
	int p=0;
	for(char c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			son[p][u]=++idx;
		}
		cnt[son[p][u]]++;
		p=son[p][u];
	}
	ennd[p]++;
}
int query(string &s) {
	int p=0,ans=0;
	for(char c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			return ans;
		}
		p=son[p][u];
		ans+=ennd[p];
	}
	return cnt[p]+ans-ennd[p];
}
void clear() {
	for(int i=0; i<=idx; i++) {
		for(int j=0; j<65; j++) {
			son[i][j]=0;
		}
		cnt[i]=0;
	}
	idx=0;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int m,n;
	cin>>m>>n;
	for(int i=1;i<=m;i++){
		int b;
		cin>>b;
		string s="";
		for(int j=1;j<=b;j++){
			int a;
			cin>>a;
			s+=(a+'0');
		}
		insert(s);
	}
	for(int i=1;i<=n;i++){
		int b;
		cin>>b;
		string s="";
		for(int i=1;i<=b;i++){
			int a;
			cin>>a;
			s+=(a+'0');
		}
		cout<<query(s)<<"\n";
	}

	return 0;
}
